1	// claim-office.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { processScenario } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  describe("quotes: basics", () => {
7	    it("should return premium 5 for a quote with an empty item list (processing fee only)", () => {
8	      const scenario = {
9	        customer: { yearsWithMHPCO: 0 },
10	        steps: [{ op: "quote", items: [] }],
11	      };
12	
13	      expect(processScenario(scenario)).toEqual({ results: [{ premium: 5 }] });
14	    });
15	    it("should return premium 115 for a single sword (100 base + 10% first-insurance + 5 fee)", () => {
16	      const scenario = {
17	        customer: { yearsWithMHPCO: 0 },
18	        steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	      };
20	
21	      expect(processScenario(scenario)).toEqual({ results: [{ premium: 115 }] });
22	    });
23	    it.todo("should return premium 71 for a single amulet (60 base)");
24	    it.todo("should return premium 93 for a single staff (80 base)");
25	    it.todo("should return premium 49 for a single potion (40 base)");
26	    it.todo("should return one result per step in the scenario");
27	  });
28	
29	  describe("quotes: components and block", () => {
30	    it.todo("should return premium 33 for a single rune (25 base, final premium rounded up)");
31	    it.todo("should return premium 60 for 2 runes (50 base, no block)");
32	    it.todo("should return premium 71 for exactly 3 runes (block rate of 60 base)");
33	    it.todo("should return premium 115 for 4 runes (100 base, block requires exactly 3)");
34	    it.todo("should return premium 198 for 7 runes (175 base, no block)");
35	    it.todo("should return premium 88 for 2 runes and 1 moonstone (75 base, no block across types)");
36	    it.todo("should return premium 137 for 3 runes and 3 moonstones (two blocks, 120 base)");
37	  });
38	
39	  describe("quotes: item modifiers", () => {
40	    it.todo("should add 50% of the item base premium for a cursed item (cursed sword -> 165)");
41	    it.todo("should add 30% of the item base premium for enchantment level 5 or higher (sword ench 5 -> 145)");
42	  });
43	
44	  describe("quotes: policy modifiers", () => {
45	    it.todo("should subtract 20% loyalty discount for customers with 2 or more years (sword, 2 years -> 95)");
46	    it.todo("should subtract 15% follow-up discount on each quote after the first in the scenario (second sword quote -> 100)");
47	  });
48	
49	  describe("quotes: integration examples", () => {
50	    it.todo("should return premium 165 for a newcomer with a cursed steel sword of enchantment 3");
51	    it.todo("should return premium 160 for a 3-year customer's second quote with a cursed steel sword of enchantment 7");
52	  });
53	
54	  describe("claims: payouts", () => {
55	    it.todo("should pay damage minus 100 deductible for a standard item (steel sword ench 3, damage 500 -> payout 400)");
56	    it.todo("should pay 100 for a rune damaged at 200");
57	    it.todo("should reimburse 50% of the damage before deductible for enchantment 8 or higher (steel sword ench 9, damage 1000 -> payout 400)");
58	    it.todo("should reimburse the full damage minus deductible for dragon material below enchantment 8 (dragon sword ench 5, damage 800 -> payout 700)");
59	    it.todo("should apply the 50% rule when both dragon material and enchantment 8+ apply (dragon sword ench 9, damage 1000 -> payout 400)");
60	    it.todo("should round the final payout down to a whole G (steel sword ench 9, damage 999 -> payout 399)");
61	  });
62	
63	  describe("claims: deductible per damaged item", () => {
64	    it.todo("should apply the deductible once per damaged item (sword damage 500 + amulet damage 300 -> payout 600)");
65	    it.todo("should apply a separate deductible to each damage entry of the same type (two insured swords, two sword damage entries)");
66	  });
67	
68	  describe("claims: payout cap", () => {
69	    it.todo("should report remainingCap as twice the insurance sum minus the payout (sword policy, claim 1500 -> payout 1400, remainingCap 600)");
70	    it.todo("should reduce the payout to the remaining cap on a later claim (second 1500 claim -> payout 600, remainingCap 0)");
71	    it.todo("should compute the cap from unmodified insurance values of all items (two swords -> cap 4000)");
72	  });
73	
74	  describe("errors", () => {
75	    it.todo("should throw for an unknown item type in a quote (e.g. broomstick)");
76	    it.todo("should throw for a damage entry whose item type is not covered by the policy");
77	    it.todo("should throw when more damage entries of a type are claimed than items of that type are covered");
78	    it.todo("should throw for a negative damage amount");
79	  });
80	});
